def count_tokens_approx(text):
    """Approximate token count (1 token ~ 4 chars for English text)."""
    return max(1, len(text) // 4)


def truncate_to_tokens(text, max_tokens):
    """Truncate text to approximately max_tokens."""
    max_chars = max_tokens * 4
    if len(text) <= max_chars:
        return text
    return text[:max_chars] + "\n... [truncated]"


def safe_json_loads(s, default=None):
    """Safely parse JSON with multiple fallback strategies."""
    try:
        return json.loads(s)
    except (json.JSONDecodeError, TypeError):
        pass
    for match in re.finditer(r'\{.*\}', s, re.DOTALL):
        try:
            return json.loads(match.group())
        except json.JSONDecodeError:
            continue
    return default


def load_python_module(path):
    """Load a Python module from file path."""
    spec = importlib.util.spec_from_file_location(Path(path).stem, path)
    if spec is None or spec.loader is None:
        raise ImportError(f"Cannot load module from {path}")
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    return module


class Scratchpad:
    """Structured scratchpad with named sections for persistent notes."""

    DEFAULT_SECTIONS = {
        "notes": "",
        "plan": "",
        "findings": "",
        "errors": "",
        "version_info": f"Running v{VERSION}",
    }

    def __init__(self, filepath):
        self.filepath = filepath
        self.sections = dict(self.DEFAULT_SECTIONS)
        self._load()

    def _load(self):
        if os.path.exists(self.filepath):
            with open(self.filepath, 'r') as f:
                data = safe_json_loads(f.read(), {})
                if isinstance(data, dict):
                    for key in self.DEFAULT_SECTIONS:
                        if key in data:
                            self.sections[key] = str(data[key])

    def save(self):
        with open(self.filepath, 'w') as f:
            json.dump(self.sections, f, indent=2)

    def get(self, section):
        return self.sections.get(section, "")

    def set(self, section, value):
        if section not in self.sections:
            self.sections[section] = ""
        self.sections[section] = value
        self.save()

    def append(self, section, text):
        current = self.get(section)
        if current:
            self.set(section, current + "\n" + text)
        else:
            self.set(section, text)

    def to_markdown(self):
        lines = ["# SCRATCHPAD", ""]
        for section, content in self.sections.items():
            if content.strip():
                lines.append(f"## {section}")
                lines.append(content)
                lines.append("")
        return "\n".join(lines)

    def to_dict(self):
        return dict(self.sections)


class MemorySystem:
