class BlockParser:
    """Improved markdown code block parser with error recovery."""

    @staticmethod
    def parse(content):
        """Parse content into list of (header, body) tuples."""
        blocks = []
        lines = content.split('\n')
        i = 0

        while i < len(lines):
            line = lines[i]
            stripped = line.strip()

            # Detect opening delimiter (3+ backticks)
            if stripped.startswith('```'):
                delim_len = 0
                for ch in stripped:
                    if ch == '`':
                        delim_len += 1
                    else:
                        break

                header = stripped[delim_len:].strip()
                body_lines = []
                i += 1
                closed = False

                while i < len(lines):
                    candidate = lines[i].strip()
                    if candidate == ('`' * delim_len) and not candidate.startswith('`' * (delim_len + 1)):
                        closed = True
                        i += 1
                        break
                    body_lines.append(lines[i])
                    i += 1

                body = '\n'.join(body_lines)
                blocks.append((header, body))
            else:
                i += 1

        return blocks


class ToolRegistry:
    """Dynamic tool loader with caching and validation."""

    def __init__(self, tools_dir):
        self.tools_dir = tools_dir
        self._cache = {}
        self._definitions = {}

    def load_all(self):
        if not os.path.exists(self.tools_dir):
            return
        for filename in os.listdir(self.tools_dir):
            if filename.endswith('.py') and not filename.startswith('_'):
                module_name = filename[:-3]
                module_path = os.path.join(self.tools_dir, filename)
                try:
                    module = load_python_module(module_path)
                    self._cache[module_name] = module
                    if hasattr(module, 'TOOL_DEFINITION'):
                        self._definitions[module_name] = module.TOOL_DEFINITION
                except Exception as e:
                    print(f"Warning: Failed to load tool {module_name}: {e}")

    def get_definitions(self):
        self.load_all()
        if not self._definitions:
            return ""
        lines = ["ADDITIONAL TOOLS (use with ```tool\\n{json}\\n```):"]
        for d in self._definitions.values():
            lines.append(json.dumps(d, indent=2))
        return "\n".join(lines)

    def execute(self, tool_name, args):
        if tool_name not in self._cache:
            self.load_all()
        if tool_name not in self._cache:
            raise ValueError(f"Unknown tool: {tool_name}")
        module = self._cache[tool_name]
        if not hasattr(module, 'execute'):
            raise ValueError(f"Tool {tool_name} has no execute function")
        return module.execute(**args)


class Planner:
    """Generates and tracks execution plans."""

    def __init__(self, scratchpad):
        self.scratchpad = scratchpad

    def generate_plan(self, goal, context, call_ollama_fn):
        prompt = (
            "You are a planning module. Given the following goal and current context, "
            "create a clear, actionable step-by-step plan.\n\n"
            f"GOAL:\n{goal}\n\n"
            f"CURRENT CONTEXT:\n{context}\n\n"
            "OUTPUT FORMAT (numbered list):\n1. First action\n2. Second action\n..."
        )
        response, _ = call_ollama_fn([{"role": "user", "content": prompt}])
        self.scratchpad.set("plan", response)
        return response

    def get_plan(self):
        return self.scratchpad.get("plan")


class Reflector:
