    def reflect(self, action, result, call_ollama_fn):
        prompt = (
            "You are a reflection module. Evaluate the following action and its result.\n"
            "Was the action successful? What could be improved? What should be done next?\n\n"
            f"ACTION:\n{action}\n\n"
            f"RESULT:\n{result}\n\n"
            "EVALUATION (be concise):\n"
        )
        response, _ = call_ollama_fn([{"role": "user", "content": prompt}])
        return response


