class AutonomousAgent:
    """Version 2 Autonomous AI Agent with planning, reflection, and structured memory."""

    def __init__(self, task_file, log_file_override=None, host_override=None, port_override=None,
                 scratchpad_file='scratchpad.json', steps=5):

        with open(task_file, 'r') as f:
            self.task = json.load(f)

        self.log_file = log_file_override or self.task.get('log_file_path', 'history_log.json')
        self.scratchpad_file = scratchpad_file
        self.host = host_override or self.task.get('ollama_host', 'localhost')
        self.port = port_override or self.task.get('ollama_port', 11434)
        self.steps = steps
        self.goal = self.task.get('goal', '')
        self.system_prompt = self.task.get('system_prompt', '')
        self.model = self.task.get('model', 'llama3')
        self.max_history_tokens = self.task.get('max_history_tokens', 30000)
        self.temperature = self.task.get('temperature', 0.5)
        self.num_ctx = self.task.get('num_ctx', 40000)
        self.num_predict = self.task.get('num_predict', 20000)
        self.retry_count = self.task.get('retry_count', 3)

        # Core systems
        self.scratchpad = Scratchpad(self.scratchpad_file)
        self.memory = MemorySystem(max_working_tokens=self.max_history_tokens, log_file=self.log_file)
        script_dir = os.path.dirname(os.path.abspath(__file__))
        self.tools = ToolRegistry(os.path.join(script_dir, "tools"))
        self.planner = Planner(self.scratchpad)
        self.reflector = Reflector(self.scratchpad)

        # State tracking
        self.step_count = 0
        self.action_history = []
        self.consecutive_errors = 0
        self.is_running = True

        self.scratchpad.set("version_info", f"Running v{VERSION}\nChanges:\n{VERSION_CHANGES.strip()}")

    def get_full_prompt(self):
        """Build the complete prompt with system, context, and history."""
        parser_instructions = (
            "PARSER RULES:\n"
            "1. To write/overwrite a file, use: ```FILEPATH\\ncontent\\n```\n"
            "2. To run shell commands (timeout mandatory): ```shell\\n# TIMEOUT 60\\ncmd\\n```\n"
            "3. To use modular tools: ```tool\\n{json}\\n```\n"
            "4. NESTED BLOCKS: If content contains triple backticks, wrap in four or more.\n"
        )

        scratchpad_md = self.scratchpad.to_markdown()
        plan = self.planner.get_plan()
        plan_section = f"\nCURRENT PLAN:\n{plan}\n" if plan else ""

        system_content = (
            f"{self.system_prompt}\n"
            f"GOAL: {self.goal}\n"
            f"{scratchpad_md}"
            f"{plan_section}"
            f"{parser_instructions}"
            f"{self.tools.get_definitions()}"
        )

        messages = [{"role": "system", "content": system_content}]
        messages.extend(self.memory.get_messages_for_prompt())
        return messages

    def call_ollama(self, messages):
        """Call the Ollama API with retry logic."""
        url = f"http://{self.host}:{self.port}/api/chat"
        payload = {
            "model": self.model,
            "messages": messages,
            "stream": False,
            "options": {
                "num_ctx": self.num_ctx,
                "temperature": self.temperature,
                "num_predict": self.num_predict,
            }
        }

        last_error = None
        for attempt in range(self.retry_count):
            try:
                response = requests.post(url, json=payload, timeout=1200)
                data = response.json()
                content = data['message']['content']
                thinking = data['message'].get('thinking', '')
                return content, thinking
            except Exception as e:
                last_error = str(e)
                if attempt < self.retry_count - 1:
                    wait_time = (attempt + 1) * 5
                    print(f"Ollama call failed (attempt {attempt+1}/{self.retry_count}): {e}. Retrying in {wait_time}s...")
                    time.sleep(wait_time)

        raise RuntimeError(f"Ollama call failed after {self.retry_count} attempts: {last_error}")

    def _execute_block(self, header, body):
        """Execute a single parsed block."""
        header = header.strip()
        if header == 'shell':
            return self._execute_shell(body)
        elif header == 'tool':
            return self._execute_tool(body)
        else:
            return self._execute_file_write(header, body)

    def _execute_shell(self, body):
        """Execute a shell command with timeout."""
        try:
            lines = body.splitlines()
            if not lines:
                return "Shell Error: Empty command"

            timeout_line = lines[0].strip()
            cmd_body = "\n".join(lines[1:]).strip()

            timeout = None
            match = re.match(r'#\s*TIMEOUT\s+(\d+)', timeout_line)
            if match:
                timeout = int(match.group(1))
            else:
                return "Shell Error: Missing or invalid timeout. Use '# TIMEOUT [seconds]' as first line."

            if timeout <= 0 or timeout > 3600:
                return f"Shell Error: Timeout must be between 1 and 3600 seconds, got {timeout}"

            proc = subprocess.run(cmd_body, shell=True, capture_output=True, text=True, timeout=timeout)
            output = proc.stdout if proc.returncode == 0 else proc.stderr
            return f"Shell Output (exit {proc.returncode}):\n{output}"
        except subprocess.TimeoutExpired:
            return f"Shell Error: Command timed out after {timeout} seconds"
        except Exception as e:
            return f"Shell Error: {str(e)}"

    def _execute_tool(self, body):
        """Execute a tool call."""
        try:
            data = safe_json_loads(body.strip())
            if not data or 'tool_name' not in data:
                return "Tool Error: Invalid tool call format."
            t_name = data.get("tool_name")
            args = data.get("args", {})
            return f"Tool {t_name} Result: {self.tools.execute(t_name, args)}"
        except Exception as e:
            return f"Tool Error: {str(e)}"

    def _execute_file_write(self, filepath, content):
        """Write content to a file."""
        try:
            abs_path = os.path.abspath(filepath)
            if not abs_path.startswith('/content') and not abs_path.startswith('/tmp'):
                return f"Write File Error: Path {filepath} is outside allowed directories (/content, /tmp)"
            dir_name = os.path.dirname(filepath)
            if dir_name:
                os.makedirs(dir_name, exist_ok=True)
            with open(filepath, 'w') as f:
                f.write(content)
            return f"Written {len(content)} bytes to {filepath}."
        except Exception as e:
            return f"Write File Error: {str(e)}"

    def parse_and_execute(self, content):
        """Parse and execute all blocks in the agent's response."""
        blocks = BlockParser.parse(content)

        if not blocks:
            text_blocks = [line.strip() for line in content.split('\n') if line.strip()]
            if text_blocks:
                return "\n".join(text_blocks[:5])
            return "No executable blocks found. Use markdown code blocks (```shell, ```tool, or ```/path/to/file)."

        results = []
        for header, body in blocks:
            try:
                result = self._execute_block(header, body)
                results.append(result)
                self.consecutive_errors = 0
            except Exception as e:
                error_msg = f"Execution Error: {str(e)}"
                results.append(error_msg)
                self.consecutive_errors += 1

        return "\n---\n".join(results)

    def run_step(self):
        """Execute a single step of the agent loop."""
        self.step_count += 1
        print(f"\n{'='*60}")
        print(f"Step {self.step_count}/{self.steps}")
        print(f"{'='*60}")

        if self.consecutive_errors >= 5:
            error_msg = f"Too many consecutive errors ({self.consecutive_errors}). Attempting recovery."
            print(error_msg)
            self.scratchpad.append("errors", error_msg)
            try:
                recovery_prompt = [
                    {"role": "system", "content": "You are a recovery assistant. The agent has encountered many errors. Suggest what to do next."},
                    {"role": "user", "content": f"Goal: {self.goal}\nRecent errors detected. What should I do? Keep it brief."}
                ]
                recovery, _ = self.call_ollama(recovery_prompt)
                print(f"Recovery suggestion: {recovery[:200]}")
                self.scratchpad.append("notes", f"Recovery: {recovery[:500]}")
                self.consecutive_errors = 0
            except Exception as e:
                print(f"Recovery failed: {e}")

        try:
            messages = self.get_full_prompt()
            content, thinking = self.call_ollama(messages)
        except Exception as e:
            error_msg = f"Model call failed: {str(e)}"
            print(error_msg)
            self.scratchpad.append("errors", error_msg)
            self.consecutive_errors += 1
            return True

        if thinking:
            print(f"[Thinking] {thinking[:200]}...")
        print(f"[Content] {content[:300]}...")

        self.memory.add_message("assistant", content)

        feedback = self.parse_and_execute(content)
        print(f"[Feedback] {feedback[:500]}...")

        self.memory.add_message("user", feedback)

        self.action_history.append({
            "step": self.step_count,
            "content_preview": content[:200],
            "feedback_preview": feedback[:200]
        })

        if self.step_count % 3 == 0:
            try:
                reflection = self.reflector.reflect(content, feedback, self.call_ollama)
                print(f"[Reflection] {reflection[:200]}...")
                self.scratchpad.append("notes", f"Reflection (step {self.step_count}): {reflection[:300]}")
            except Exception as e:
                print(f"Reflection failed: {e}")

        self.memory.compress(self.call_ollama)
        self.memory.save()
        self.scratchpad.save()

        return True

    def run(self):
        """Main agent loop."""
        print(f"Starting Autonomous Agent v{VERSION}")
        print(f"Goal: {self.goal[:200]}...")
        print(f"Model: {self.model}")
        print(f"Steps: {self.steps}")
        print()

        if not self.planner.get_plan():
            print("Generating initial plan...")
            try:
                plan = self.planner.generate_plan(
                    self.goal,
                    f"Starting fresh. Scratchpad sections: {list(self.scratchpad.sections.keys())}",
                    self.call_ollama
                )
                print(f"Plan: {plan[:300]}...")
            except Exception as e:
                print(f"Planning failed: {e}")

        while self.is_running and self.step_count < self.steps:
            if not self.run_step():
                break
            time.sleep(0.5)

        print(f"\nAgent finished after {self.step_count} steps.")


